func (f *filterOrmDecorator) DBStats() *sql.DBStats {
	inv := &Invocation{
		Method:		"DBStats",
		InsideTx:	f.insideTx,
		TxStartTime:	f.txStartTime,
		f: func(c context.Context) []interface{} {
			res := f.ormer.DBStats()
			return []interface{}{res}
		},
	}
	res := f.root(context.Background(), inv)

	if res[0] == nil {
		return nil
	}

	return res[0].(*sql.DBStats)
}
